    for (let i = 1; i < n; i++) {
        const prev_valid_nums = validNumbers[i - 1];
        const current_valid_nums = validNumbers[i];

        const dp_next = new Array(current_valid_nums.length).fill(0n);

        for (let j = 0; j < current_valid_nums.length; j++) {
            const current_num = current_valid_nums[j];
