            let sum_prev_counts = 0n;

            // Find the index of the last element in prev_valid_nums that is <= current_num
            let upper_bound_index = -1;
            let low = 0;
            let high = prev_valid_nums.length - 1;

            while(low <= high) {
                const mid = Math.floor((low + high) / 2);
                if (prev_valid_nums[mid] <= current_num) {
