            for (let k = 0; k <= upper_bound_index; k++) {
                sum_prev_counts = (sum_prev_counts + dp_current[k]) % MOD;
            }

            dp_next[j] = sum_prev_counts;
        }

        dp_current = dp_next;
    }

    // Step 3: Final result
    let totalCount = 0n;
    for (const count of dp_current) {
        totalCount = (totalCount + count) % MOD;
    }

    return Number(totalCount);
